// AgentServiceHandler is an implementation of the stackpanel.agent.AgentService service.
type AgentServiceHandler interface {
	// Project
	GetProject(context.Context, *connect.Request[gopb.GetProjectRequest]) (*connect.Response[gopb.GetProjectResponse], error)
	// Config entities - generic CRUD for Nix data files
	GetConfig(context.Context, *connect.Request[gopb.GetConfigRequest]) (*connect.Response[gopb.Config], error)
	SetConfig(context.Context, *connect.Request[gopb.Config]) (*connect.Response[gopb.Config], error)
	GetSecrets(context.Context, *connect.Request[gopb.GetSecretsRequest]) (*connect.Response[gopb.Secrets], error)
	SetSecrets(context.Context, *connect.Request[gopb.Secrets]) (*connect.Response[gopb.Secrets], error)
	GetUsers(context.Context, *connect.Request[gopb.GetUsersRequest]) (*connect.Response[gopb.Users], error)
	SetUsers(context.Context, *connect.Request[gopb.Users]) (*connect.Response[gopb.Users], error)
	GetAws(context.Context, *connect.Request[gopb.GetAwsRequest]) (*connect.Response[gopb.Aws], error)
	SetAws(context.Context, *connect.Request[gopb.Aws]) (*connect.Response[gopb.Aws], error)
	GetApps(context.Context, *connect.Request[gopb.GetAppsRequest]) (*connect.Response[gopb.Apps], error)
	SetApps(context.Context, *connect.Request[gopb.Apps]) (*connect.Response[gopb.Apps], error)
	GetVariables(context.Context, *connect.Request[gopb.GetVariablesRequest]) (*connect.Response[gopb.Variables], error)
	SetVariables(context.Context, *connect.Request[gopb.Variables]) (*connect.Response[gopb.Variables], error)
	// Identity management (local decryption key)
	GetAgeIdentity(context.Context, *connect.Request[gopb.GetAgeIdentityRequest]) (*connect.Response[gopb.AgeIdentityResponse], error)
	SetAgeIdentity(context.Context, *connect.Request[gopb.SetAgeIdentityRequest]) (*connect.Response[gopb.AgeIdentityResponse], error)
	// KMS configuration
	GetKMSConfig(context.Context, *connect.Request[gopb.GetKMSConfigRequest]) (*connect.Response[gopb.KMSConfigResponse], error)
	SetKMSConfig(context.Context, *connect.Request[gopb.SetKMSConfigRequest]) (*connect.Response[gopb.KMSConfigResponse], error)
	// File operations
	ReadFile(context.Context, *connect.Request[gopb.ReadFileRequest]) (*connect.Response[gopb.ReadFileResponse], error)
	WriteFile(context.Context, *connect.Request[gopb.WriteFileRequest]) (*connect.Response[gopb.WriteFileResponse], error)
	ListFiles(context.Context, *connect.Request[gopb.ListFilesRequest]) (*connect.Response[gopb.ListFilesResponse], error)
	// Command execution
	Exec(context.Context, *connect.Request[gopb.ExecRequest]) (*connect.Response[gopb.ExecResponse], error)
	// Nix operations
	NixGenerate(context.Context, *connect.Request[gopb.NixGenerateRequest]) (*connect.Response[gopb.NixGenerateResponse], error)
	NixEval(context.Context, *connect.Request[gopb.NixEvalRequest]) (*connect.Response[gopb.NixEvalResponse], error)
	// Services (process-compose)
	GetServicesStatus(context.Context, *connect.Request[gopb.GetServicesStatusRequest]) (*connect.Response[gopb.GetServicesStatusResponse], error)
	StartService(context.Context, *connect.Request[gopb.ServiceRequest]) (*connect.Response[gopb.ServiceResponse], error)
	StopService(context.Context, *connect.Request[gopb.ServiceRequest]) (*connect.Response[gopb.ServiceResponse], error)
	RestartService(context.Context, *connect.Request[gopb.ServiceRequest]) (*connect.Response[gopb.ServiceResponse], error)
	// SST Infrastructure
	GetSSTStatus(context.Context, *connect.Request[gopb.GetSSTStatusRequest]) (*connect.Response[gopb.SSTStatusResponse], error)
	GetSSTConfig(context.Context, *connect.Request[gopb.GetSSTConfigRequest]) (*connect.Response[gopb.Sst], error)
	DeploySST(context.Context, *connect.Request[gopb.DeploySSTRequest]) (*connect.Response[gopb.DeploySSTResponse], error)
	RemoveSST(context.Context, *connect.Request[gopb.RemoveSSTRequest]) (*connect.Response[gopb.RemoveSSTResponse], error)
	GetSSTOutputs(context.Context, *connect.Request[gopb.GetSSTOutputsRequest]) (*connect.Response[gopb.SSTOutputsResponse], error)
	GetSSTResources(context.Context, *connect.Request[gopb.GetSSTResourcesRequest]) (*connect.Response[gopb.SSTResourcesResponse], error)
	// Nixpkgs package management
	SearchNixpkgs(context.Context, *connect.Request[gopb.SearchNixpkgsRequest]) (*connect.Response[gopb.SearchNixpkgsResponse], error)
	GetInstalledPackages(context.Context, *connect.Request[gopb.GetInstalledPackagesRequest]) (*connect.Response[gopb.InstalledPackagesResponse], error)
	// Process-compose processes
	GetProcesses(context.Context, *connect.Request[gopb.GetProcessesRequest]) (*connect.Response[gopb.GetProcessesResponse], error)
	// Healthchecks
	GetHealthchecks(context.Context, *connect.Request[gopb.GetHealthchecksRequest]) (*connect.Response[gopb.HealthchecksResponse], error)
	// Full Nix config (evaluated from flake)
	GetNixConfig(context.Context, *connect.Request[gopb.GetNixConfigRequest]) (*connect.Response[gopb.NixConfigResponse], error)
	RefreshNixConfig(context.Context, *connect.Request[gopb.RefreshNixConfigRequest]) (*connect.Response[gopb.NixConfigResponse], error)
}

